import React, { useEffect, useState } from 'react';
import { GoogleMap, LoadScript, Marker } from '@react-google-maps/api';
import WebSocketService from '../services/WebSocketService';
import api from '../services/api';
import mapStyles from '../components/mapStyles';

const containerStyle = {
  width: '100%',
  height: '600px',
};

const center = {
  lat: 37.7749,
  lng: -122.4194,
};

const LiveTracking = () => {
  const [vehicles, setVehicles] = useState([]);
  const [filter, setFilter] = useState('all');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch initial vehicle data
    const fetchVehicles = async () => {
      try {
        const response = await api.get('/vehicles');
        setVehicles(response.data);
        setLoading(false);
      } catch (err) {
        console.error('Error fetching vehicles:', err);
        setLoading(false);
      }
    };

    fetchVehicles();

    // Subscribe to WebSocket for real-time updates
    WebSocketService.connect();
    WebSocketService.subscribe('/topic/vehicles', (message) => {
      const vehicleData = JSON.parse(message.body);
      setVehicles((prev) => [...prev.filter(v => v.id !== vehicleData.id), vehicleData]);
    });

    return () => WebSocketService.disconnect();
  }, []);

  const filteredVehicles = filter === 'all' ? vehicles : vehicles.filter(v => v.status === filter);

  return (
    <div className="space-y-6">
      <h2 className="g-title">Live Vehicle Tracking</h2>
      <div className="flex space-x-4 mb-4">
        <select
          className="g-input"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="all">All Vehicles</option>
          <option value="ACTIVE">Active</option>
          <option value="IDLE">Idle</option>
          <option value="MAINTENANCE">Maintenance</option>
        </select>
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Map</h3>
          {loading ? (
            <p className="text-gray-600">Loading map...</p>
          ) : (
            <LoadScript googleMapsApiKey="AIzaSyCKgddaxzo_Fu2edk6qyN4g4qqEAvFcAaY">
              <GoogleMap
                mapContainerStyle={containerStyle}
                center={center}
                zoom={10}
                options={{ styles: mapStyles }}
              >
                {filteredVehicles.map((vehicle, index) => (
                  <Marker
                    key={index}
                    position={{ lat: vehicle.lat, lng: vehicle.lng }}
                    label={vehicle.id}
                    title={`Status: ${vehicle.status}`}
                  />
                ))}
              </GoogleMap>
            </LoadScript>
          )}
        </div>
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle List</h3>
          {filteredVehicles.length === 0 ? (
            <p className="text-gray-600">No vehicles found.</p>
          ) : (
            <div className="overflow-y-auto max-h-[500px]">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-gray-100">
                    <th className="p-2">ID</th>
                    <th className="p-2">Status</th>
                    <th className="p-2">Location</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredVehicles.map((vehicle, index) => (
                    <tr key={index} className="border-b">
                      <td className="p-2">{vehicle.id}</td>
                      <td className="p-2">{vehicle.status}</td>
                      <td className="p-2">{`(${vehicle.lat}, ${vehicle.lng})`}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LiveTracking;
